struct HitMarker {
    bool isVisible;
    float displayTime;
    float maxDisplayTime;
    bool isHeadshot;
    bool isKill;
};

void TriggerHitMarker(HitMarker& marker, bool headshot, bool kill) {
    marker.isVisible = true;
    marker.displayTime = marker.maxDisplayTime;
    marker.isHeadshot = headshot;
    marker.isKill = kill;
}

void UpdateHitMarker(HitMarker& marker, float deltaTime) {
    if (marker.isVisible) {
        marker.displayTime -= deltaTime;
        if (marker.displayTime <= 0) {
            marker.isVisible = false;
        }
    }
}

void DrawHitMarker(const HitMarker& marker) {
    if (!marker.isVisible) return;

    Vector2 center = {GetScreenWidth() / 2.0f, GetScreenHeight() / 2.0f};

    float alpha = marker.displayTime / marker.maxDisplayTime;
    float size = 12.0f;
    float gap = 6.0f;

    // تحديد اللون
    Color markerColor;
    if (marker.isKill) {
        markerColor = Color{255, 50, 50, (unsigned char)(alpha * 255)};  // أحمر للقتل
        size = 16.0f;
    } else if (marker.isHeadshot) {
        markerColor = Color{255, 200, 0, (unsigned char)(alpha * 255)};  // ذهبي لرأس الرأس
        size = 14.0f;
    } else {
        markerColor = Color{255, 255, 255, (unsigned char)(alpha * 255)};  // أبيض عادي
    }

    float thickness = 2.0f;

    // رسم أربعة خطوط
    // أعلى
    DrawLine(center.x, center.y - gap, center.x, center.y - gap - size, markerColor);
    // أسفل
    DrawLine(center.x, center.y + gap, center.x, center.y + gap + size, markerColor);
    // يسار
    DrawLine(center.x - gap, center.y, center.x - gap - size, center.y, markerColor);
    // يمين
    DrawLine(center.x + gap, center.y, center.x + gap + size, center.y, markerColor);

    // نقطة مركزية للقتل
    if (marker.isKill) {
        DrawCircleV(center, 4, markerColor);
    }
}

struct AchievementPopup {
    bool isActive;
    const char* title;
    const char* description;
    Texture2D icon;
    float displayTime;
    float maxDisplayTime;
    float slideProgress;  // 0 = مخفي, 1 = ظاهر
};

void TriggerAchievement(AchievementPopup& popup, const char* title, const char* desc, Texture2D icon) {
    popup.title = title;
    popup.description = desc;
    popup.icon = icon;
    popup.displayTime = popup.maxDisplayTime;
    popup.isActive = true;
    popup.slideProgress = 0;

    // تشغيل صوت الإنجاز
    PlaySound(achievementSound);
}

void UpdateAchievementPopup(AchievementPopup& popup, float deltaTime) {
    if (!popup.isActive) return;

    // انيميشن الظهور
    if (popup.displayTime > popup.maxDisplayTime - 0.3f) {
        popup.slideProgress += deltaTime * 4.0f;
    }
    // انيميشن الاختفاء
    else if (popup.displayTime < 0.5f) {
        popup.slideProgress -= deltaTime * 3.0f;
    }

    popup.slideProgress = Clamp(popup.slideProgress, 0.0f, 1.0f);

    popup.displayTime -= deltaTime;
    if (popup.displayTime <= 0) {
        popup.isActive = false;
    }
}

void DrawAchievementPopup(AchievementPopup& popup) {
    if (!popup.isActive || popup.slideProgress <= 0) return;

    float screenWidth = GetScreenWidth();
    float screenHeight = GetScreenHeight();

    float popupWidth = 320;
    float popupHeight = 80;
    float startY = screenHeight + 10;  // أسفل الشاشة
    float endY = screenHeight - popupHeight - 20;  // الموضع النهائي

    float currentY = startY + (endY - startY) * EaseOutBack(popup.slideProgress);

    Rectangle popupRect = {screenWidth - popupWidth - 20, currentY, popupWidth, popupHeight};

    // خلفية مع تدرج
    DrawRectangleRounded(popupRect, 0.2f, 8, Color{30, 30, 40, 230});
    DrawRectangleRoundedLines(popupRect, 0.2f, 8, Color{200, 170, 50});

    // شريط ذهبي علوي
    Rectangle topBar = {popupRect.x, popupRect.y, popupRect.width, 4};
    DrawRectangleRec(topBar, Color{200, 170, 50});

    // نص "إنجاز مفتوح!"
    DrawText("🏆 إنجاز مفتوح!", popupRect.x + 70, popupRect.y + 12, 12, Color{200, 170, 50});

    // عنوان الإنجاز
    DrawText(popup.title, popupRect.x + 70, popupRect.y + 30, 16, Color{255, 255, 255});

    // الوصف
    DrawText(popup.description, popupRect.x + 70, popupRect.y + 52, 12, Color{150, 150, 150});

    // الأيقونة
    Rectangle iconRect = {popupRect.x + 10, popupRect.y + 10, 50, 50};
    DrawTexturePro(popup.icon, {0, 0, (float)popup.icon.width, (float)popup.icon.height},
                   iconRect, {0, 0}, 0, Color{255, 255, 255});
}

float EaseOutBack(float t) {
    float c1 = 1.70158f;
    float c3 = c1 + 1;
    return 1 + c3 * powf(t - 1, 3) + c1 * powf(t - 1, 2);
}

struct DamageOverlay {
    float healthPercent;
    float recentDamage;    // الضرر الأخير (للتأثير المؤقت)
};

void UpdateDamageOverlay(DamageOverlay& overlay, float currentHealth, float maxHealth, float deltaTime) {
    overlay.healthPercent = currentHealth / maxHealth;
    overlay.pulseTime += deltaTime;

    // تناقص الضرر الأخير
    if (overlay.recentDamage > 0) {
        overlay.recentDamage -= deltaTime * 2.0f;
        if (overlay.recentDamage < 0) overlay.recentDamage = 0;
    }
}

void TakeDamage(DamageOverlay& overlay, float damage) {
    overlay.recentDamage = fminf(overlay.recentDamage + damage * 0.01f, 1.0f);
}

void DrawDamageOverlay(const DamageOverlay& overlay) {
    int screenWidth = GetScreenWidth();
    int screenHeight = GetScreenHeight();

    // شدة التراكب تعتمد على الصحة المنخفضة + الضرر الأخير
    float lowHealthIntensity = 1.0f - overlay.healthPercent;
    float totalIntensity = fminf(lowHealthIntensity + overlay.recentDamage, 1.0f);

    if (totalIntensity <= 0.01f) return;

    // نبض عند الصحة المنخفضة
    if (overlay.healthPercent < 0.3f) {
        float pulse = sinf(overlay.pulseTime * 4.0f) * 0.3f + 0.7f;
        totalIntensity *= pulse;
    }

    unsigned char alpha = (unsigned char)(totalIntensity * 150);

    // رسم الحواف الحمراء
    int edgeSize = (int)(100 * totalIntensity);

    // أعلى
    for (int i = 0; i < edgeSize; i++) {
        float edgeAlpha = 1.0f - (float)i / edgeSize;
        DrawLine(0, i, screenWidth, i, Color{150, 0, 0, (unsigned char)(alpha * edgeAlpha)});
    }

    // أسفل
    for (int i = 0; i < edgeSize; i++) {
        float edgeAlpha = 1.0f - (float)i / edgeSize;
        DrawLine(0, screenHeight - i, screenWidth, screenHeight - i,
                Color{150, 0, 0, (unsigned char)(alpha * edgeAlpha)});
    }

    // يسار
    for (int i = 0; i < edgeSize; i++) {
        float edgeAlpha = 1.0f - (float)i / edgeSize;
        DrawLine(i, 0, i, screenHeight, Color{150, 0, 0, (unsigned char)(alpha * edgeAlpha)});
    }

    // يمين
    for (int i = 0; i < edgeSize; i++) {
        float edgeAlpha = 1.0f - (float)i / edgeSize;
        DrawLine(screenWidth - i, 0, screenWidth - i, screenHeight,
                Color{150, 0, 0, (unsigned char)(alpha * edgeAlpha)});
    }
}
